<?php
if (!defined('ABSPATH')) exit;
function cdp_render_assignments_page(){ if(!current_user_can('manage_options')) return; global $wpdb; $p=cdp_table('products'); $v=cdp_table('product_versions'); $a=cdp_table('assignments');
 if(isset($_POST['cdp_add_assignment'])){ check_admin_referer('cdp_add_assignment'); $user_id=absint($_POST['user_id']??0); $product_id=absint($_POST['product_id']??0); $version_id=absint($_POST['version_id']??0)?:null; $max=absint($_POST['max_downloads']??0); $ex=sanitize_text_field($_POST['expires_at']??''); $expires=$ex?date('Y-m-d H:i:s',strtotime($ex)):null; $product_exists=$product_id?(int)$wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM $p WHERE id=%d",$product_id)):0; $version_matches=true; if($version_id){ $version_matches=(int)$wpdb->get_var($wpdb->prepare("SELECT COUNT(*) FROM $v WHERE id=%d AND product_id=%d AND active=1",$version_id,$product_id))>0; } if($user_id&&$product_exists&&get_user_by('id',$user_id)&&$version_matches){ $wpdb->insert($a,['user_id'=>$user_id,'product_id'=>$product_id,'version_id'=>$version_id,'token'=>cdp_generate_token(),'expires_at'=>$expires,'max_downloads'=>$max,'download_count'=>0,'created_by'=>get_current_user_id(),'created_at'=>current_time('mysql')]); echo '<div class="updated"><p>Product assigned.</p></div>'; } elseif(!$version_matches) echo '<div class="error"><p>Version ID must belong to the selected product.</p></div>'; else echo '<div class="error"><p>Valid user and product are required.</p></div>'; }
 if(isset($_POST['cdp_delete_assignment'])){ check_admin_referer('cdp_delete_assignment'); $wpdb->delete($a,['id'=>absint($_POST['assignment_id'])]); echo '<div class="updated"><p>Assignment removed.</p></div>'; }
 $products=$wpdb->get_results("SELECT id,title FROM $p ORDER BY title"); $versions=$wpdb->get_results("SELECT id,product_id,version_label FROM $v ORDER BY product_id,id DESC"); $rows=$wpdb->get_results("SELECT a.*, p.title, v.version_label FROM $a a JOIN $p p ON p.id=a.product_id LEFT JOIN $v v ON v.id=a.version_id ORDER BY a.id DESC LIMIT 300"); ?>
 <div class="wrap"><h1>Assignments</h1><p>Assign a product to a WordPress user. Version is optional; if empty, the portal uses the latest active product version.</p><form method="post"><?php wp_nonce_field('cdp_add_assignment'); ?><table class="form-table"><tr><th>User ID</th><td><input type="number" name="user_id" required> <span class="description">WordPress user ID.</span></td></tr><tr><th>Product</th><td><select name="product_id" required><option value="">Select product</option><?php foreach($products as $x) echo '<option value="'.esc_attr($x->id).'">'.esc_html($x->title).'</option>'; ?></select></td></tr><tr><th>Version ID</th><td><input type="number" name="version_id"> <span class="description">Optional. Available version IDs: <?php echo esc_html(implode(', ', array_map(fn($r)=>$r->id.'='.$r->version_label, $versions))); ?></span></td></tr><tr><th>Max downloads</th><td><input type="number" name="max_downloads" value="0" min="0"> <span class="description">0 = unlimited</span></td></tr><tr><th>Expires at</th><td><input type="datetime-local" name="expires_at"></td></tr></table><p><button class="button button-primary" name="cdp_add_assignment" value="1">Assign Product</button></p></form>
 <h2>Recent Assignments</h2><table class="widefat striped"><thead><tr><th>ID</th><th>User</th><th>Product</th><th>Version</th><th>Downloads</th><th>Expires</th><th>Action</th></tr></thead><tbody><?php foreach($rows as $r): $u=get_user_by('id',$r->user_id); ?><tr><td><?php echo esc_html($r->id); ?></td><td><?php echo esc_html($u?$u->user_login.' (#'.$r->user_id.')':'#'.$r->user_id); ?></td><td><?php echo esc_html($r->title); ?></td><td><?php echo esc_html($r->version_label ?: 'Latest'); ?></td><td><?php echo esc_html($r->download_count.'/'.($r->max_downloads?:'∞')); ?></td><td><?php echo esc_html($r->expires_at ?: 'Never'); ?></td><td><form method="post"><?php wp_nonce_field('cdp_delete_assignment'); ?><input type="hidden" name="assignment_id" value="<?php echo esc_attr($r->id); ?>"><button class="button" name="cdp_delete_assignment" value="1">Remove</button></form></td></tr><?php endforeach; ?></tbody></table></div><?php }
